sharedContracts.interfaceSketch:
// Payload carried inside the existing IpcStreamMessage (src/shared/types.ts:734),
// whose `stream: IpcStreamKind` is 'progress' (stage) or 'delta' (token) — no new wire kind (k2).
type ProgressOperation = 'workflow.run' | 'analyze.run';

interface StageProgressEvent {
  kind: 'stage';
  operation: ProgressOperation;
  stageId: string;         // stable id of the internal stage now executing
  stageLabel: string;      // human-facing label for that stage
  index: number;           // 0-based ordinal of the current stage
  total: number | null;    // known stage count, or null when not enumerable
}

interface TokenProgressEvent {
  kind: 'token';
  operation: ProgressOperation;
  stageId: string | null;  // stage the tokens belong to, when known
  tokensDelta: number;     // tokens produced since the previous token event
  tokensTotal: number;     // cumulative tokens for this operation
}

type ProgressEvent = StageProgressEvent | TokenProgressEvent;

// Caller opts in by supplying the standard MCP progress token in request _meta.
interface LongRunningToolMeta {
  progressToken?: string | number; // absent => no progress notifications emitted (s2 ac2)
}

// Emitted per inbound ProgressEvent frame, only when a progressToken was supplied.
interface McpProgressNotification {
  method: 'notifications/progress';
  params: {
    progressToken: string | number; // echoes the caller's token (k3)
    progress: number;               // monotonic advance (e.g. tokensTotal or stage index)
    total?: number;                 // stage total when known
    message?: string;               // derived from stageLabel / token delta (s2 ac3)
  };
}

// Thin typed reader the RPC client exposes over decoded ProgressEvent frames.
// Type-level surface only; the fork supplies the implementation and render.
interface DaemonProgressReader {
  onStage(handler: (event: StageProgressEvent) => void): void;
  onToken(handler: (event: TokenProgressEvent) => void): void;
  onComplete(handler: () => void): void;   // fires once when final result arrives; no events after
}

interface DaemonProgressSnapshot {
  operation: ProgressOperation;
  currentStage: StageProgressEvent | null;
  tokensTotal: number;
  done: boolean;
}
